fun main() {
    // Creates a list we are allowed to modify
    val cart = mutableListOf("Apple", "Banana")

    cart.add("Orange")      // Appends to the end
    cart.remove("Banana")   // Removes exactly "Banana"
    cart[0] = "Pear"        // Overwrites the first item

    println(cart) // Prints: [Pear, Orange]
}
